1	export type Cell = [x: number, y: number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const countLiveNeighbors = (cells: Cell[]): Map<string, { cell: Cell; count: number }> => {
15	  const counts = new Map<string, { cell: Cell; count: number }>();
16	  for (const cell of cells) {
17	    for (const neighbor of neighborsOf(cell)) {
18	      const key = cellKey(neighbor);
19	      const existing = counts.get(key);
20	      if (existing) existing.count += 1;
21	      else counts.set(key, { cell: neighbor, count: 1 });
22	    }
23	  }
24	  return counts;
25	};
26	
27	const survives = (count: number): boolean => count === 2 || count === 3;
28	const isBorn = (count: number): boolean => count === 3;
29	
30	export function nextGeneration(cells: Cell[]): Cell[] {
31	  const liveKeys = new Set(cells.map(cellKey));
32	  const neighborCounts = countLiveNeighbors(cells);
33	
34	  const nextGen: Cell[] = [];
35	  for (const [key, { cell, count }] of neighborCounts) {
36	    const wasAlive = liveKeys.has(key);
37	    if (wasAlive ? survives(count) : isBorn(count)) {
38	      nextGen.push(cell);
39	    }
40	  }
41	  return nextGen;
42	}
